`timescale 1ns / 1ps
module CNN_top(
input       wire                        clk,    
input       wire                        enable,
input       wire                        rst_n,
input       wire signed [55:0]          data_in,//输入特征图，每次7*8bit
output      reg                         enable_out,
output      wire signed [63:0]          data_out//最终注意力分数，两个32bit拼接
    );
    
reg [7:0] cnt;
genvar i;

always @(posedge clk or negedge rst_n)begin
    if(!rst_n)
        cnt <= 7'b0;
    else if(enable)
        cnt <= cnt + 1;
    else
        cnt <= cnt;
end

always @(posedge clk or negedge rst_n)begin
    if(!rst_n)
        enable_out <= 1'b0;
    else if(cnt == 8'd152 ||cnt == 8'd153)//输出使能在T153和T154两个周期拉高，输出两个注意力分数
        enable_out <= 1'b1;
    else
        enable_out <= 1'b0;
end

//SA1第一层卷积
